}
if (Test-Path 'C:\Users\1\AppData\Local\moysklad-kassa-updater') {
  Remove-Item 'C:\Users\1\AppData\Local\moysklad-kassa-updater' -Recurse -Force -EA SilentlyContinue
}
L "Updater blocked"

# D) Fix ESM/KKT chain - stop fptr10_t, restart grpc+ESM
Stop-Process -Name fptr10_t -Force -EA SilentlyContinue
Restart-Service atol-grpc-service,esm-orchestrator,esm-cm-00106107290460 -Force -EA SilentlyContinue
Start-Sleep 8

# Start fptr10_t for ESM mode (needed for grpc bridge)
Start-Process 'C:\Program Files (x86)\ATOL\Drivers10\KKT\bin\fptr10_t.exe'
Start-Sleep 15

try {
  $dk = Invoke-RestMethod 'http://127.0.0.1:51077/api/v1/dkktList' -TimeoutSec 10
  L "dkktList after fix: $($dk | ConvertTo-Json -Compress -Depth 4)"
} catch { L "dkktList still fail: $($_.Exception.Message)" }

# ESM CM log
$cmLog = Get-ChildItem 'C:\ProgramData\ESP' -Recurse -Filter '*.log' -EA SilentlyContinue | 
  Where-Object { $_.FullName -match 'control|cm|001061' } | Sort LastWriteTime -Desc | Select -First 1
if ($cmLog) { Get-Content $cmLog.FullName -Tail 15 | ForEach-Object { L "CM: $_" } }

# E) Start kassa
$psi = New-Object System.Diagnostics.ProcessStartInfo
$psi.FileName = 'C:\Program Files (x86)\moysklad-kassa\kassa.exe'
$psi.WorkingDirectory = 'C:\Program Files (x86)\moysklad-kassa'
$psi.UseShellExecute = $true
[Environment]::SetEnvironmentVariable('APPDATA','C:\Users\1\AppData\Roaming','Process')
[Environment]::SetEnvironmentVariable('USERPROFILE','C:\Users\1','Process')
Start-Process $psi
L "Kassa launched"
Start-Sleep 50

# F) Check NEW log entries only (after restart)
$logFile='C:\Users\1\AppData\Roaming\moysklad-kassa\app.log.2026-07-09'
$cutoff = (Get-Date).AddMinutes(-3)
Get-Content $logFile -Tail 30 | ForEach-Object {
  try {
    $j = $_ | ConvertFrom-Json
    if ($j.timestamp) {
      $ts = [DateTime]::Parse($j.timestamp)
      if ($ts -gt $cutoff) { L "NEW: [$($j.logger)] $($j.message)" }
    }
  } catch {}
}

L "Kassa procs: $((Get-Process kassa -EA SilentlyContinue).Count)"
L "=== PHASE 3 DONE ==="
}

