$js=@"
(async () => {
 const sleep = ms => new Promise(r=>setTimeout(r,ms));
 const setVal = (el,v) => { const d=Object.getOwnPropertyDescriptor(HTMLInputElement.prototype,'value'); d.set.call(el,v); el.dispatchEvent(new Event('input',{bubbles:true})); el.dispatchEvent(new Event('change',{bubbles:true})); };
 await sleep(1500);
 let user=document.querySelector('input[type=text],input[type=email],input[name=j_username]');
 let pwd=document.querySelector('input[type=password],input[name=j_password]');
 if(!user||!pwd){ const all=[...document.querySelectorAll('input')]; user=all.find(i=>i.type!=='password'&&i.type!=='hidden'&&i.offsetParent); pwd=all.find(i=>i.type==='password'); }
 if(user&&pwd){ setVal(user,'$login'); setVal(pwd,'$pass'); await sleep(800); const btn=[...document.querySelectorAll('button')].find(b=>/войти/i.test(b.textContent||'')); if(btn) btn.click(); await sleep(12000); }
 return {href:location.href,title:document.title,text:(document.body&&document.body.innerText||'').slice(0,400)};
})()
"@
$loginRes = Eval-Js $js
"LOGIN=$($loginRes | ConvertTo-Json -Compress)"
$fetchStores=@'
(async () => {
  const out={href:location.href,title:document.title};
  const r = await fetch('https://online.moysklad.ru/api/remap/1.2/entity/retailstore?limit=1000', {credentials:'include'});
  out.status = r.status;
  const j = await r.json();
  out.rows = (j.rows||[]).map(x => ({id:x.id,name:x.name,active:x.active,archived:x.archived,authTokenAttached:x.authTokenAttached,updated:x.updated,state:x.state,environment:x.environment}));
  return out;
})()
'@
$stores = Eval-Js $fetchStores
$stores | ConvertTo-Json -Depth 20

$tabs = Invoke-RestMethod 'http://127.0.0.1:9223/json/list' -TimeoutSec 15
$page = $tabs | Where-Object { $_.type -eq 'page' } | Select-Object -First 1
$wsUrl = $page.webSocketDebuggerUrl
$script:msgId=0
function Send-CdpCommand([string]$Method,[hashtable]$Params){ $script:msgId++; $id=$script:msgId; $client=New-Object System.Net.WebSockets.ClientWebSocket; $ct=New-Object System.Threading.CancellationToken; $client.ConnectAsync([Uri]$wsUrl,$ct).Wait(20000)|Out-Null; $payload=@{id=$id;method=$Method;params=$Params}|ConvertTo-Json -Compress -Depth 50; $bytes=[Text.Encoding]::UTF8.GetBytes($payload); $seg=[ArraySegment[byte]]::new($bytes); $client.SendAsync($seg,[System.Net.WebSockets.WebSocketMessageType]::Text,$true,$ct).Wait(20000)|Out-Null; $buf=New-Object byte[] 1048576; $deadline=(Get-Date).AddSeconds(60); while((Get-Date)-lt $deadline){ $segR=[ArraySegment[byte]]::new($buf); $res=$client.ReceiveAsync($segR,$ct).Result; $text=[Text.Encoding]::UTF8.GetString($buf,0,$res.Count); $obj=$text | ConvertFrom-Json; if($obj.id -eq $id){ $client.CloseAsync([System.Net.WebSockets.WebSocketCloseStatus]::NormalClosure,'done',$ct).Wait(5000)|Out-Null; return $obj } } throw 'timeout' }
function Eval-Js([string]$Expression){ $r=Send-CdpCommand 'Runtime.evaluate' @{expression=$Expression;awaitPromise=$true;returnByValue=$true}; if($r.result.exceptionDetails){ throw ($r.result.exceptionDetails.text) }; $r.result.result.value }
$expr=@'
(async () => {
  const urls = [
    'https://api.moysklad.ru/api/remap/1.2/entity/retailstore?limit=3',
    'https://online.moysklad.ru/api/remap/1.2/entity/retailstore?limit=3',
    'https://online.moysklad.ru/api/posap/1.0/settings/retailstore/'
  ];
  const out=[];
  for (const url of urls){
    try {
      const r = await fetch(url,{credentials:'include',headers:{Accept:'application/json'}});
      const text = await r.text();
      out.push({url,status:r.status,snippet:text.slice(0,500)});
    } catch(e){ out.push({url,error:String(e)}) }
  }
  return out;
})()
'@
Eval-Js $expr | ConvertTo-Json -Depth 10
